 1→import React from 'react';
 2→import {
 3→  TouchableOpacity,
 4→  Text,
 5→  ActivityIndicator,
 6→  StyleSheet,
 7→  type ViewStyle,
 8→  type TextStyle,
 9→} from 'react-native';
10→import * as Haptics from 'expo-haptics';
11→import { theme } from '../../theme';
12→
13→interface ButtonProps {
14→  title: string;
15→  onPress: () => void;
16→  variant?: 'primary' | 'secondary' | 'outline' | 'danger' | 'ghost';
17→  loading?: boolean;
18→  disabled?: boolean;
19→  style?: ViewStyle;
20→  textStyle?: TextStyle;
21→  size?: 'sm' | 'md' | 'lg';
22→}
23→
24→export function Button({
25→  title,
26→  onPress,
27→  variant = 'primary',
28→  loading = false,
29→  disabled = false,
30→  style,
31→  textStyle,
32→  size = 'md',
33→}: ButtonProps) {
34→  const handlePress = async () => {
35→    if (disabled || loading) return;
36→    await Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
37→    onPress();
38→  };
39→
40→  const sizeStyles = {
41→    sm: { paddingVertical: 8, paddingHorizontal: 16, fontSize: 13 },
42→    md: { paddingVertical: 12, paddingHorizontal: 20, fontSize: 15 },
43→    lg: { paddingVertical: 16, paddingHorizontal: 28, fontSize: 17 },
44→  };
45→
46→  const variantStyles: Record<string, { bg: string; text: string; border?: string }> = {
47→    primary: { bg: theme.colors.primary, text: '#ffffff' },
48→    secondary: { bg: theme.colors.secondary, text: '#ffffff' },
49→    outline: { bg: 'transparent', text: theme.colors.primary, border: theme.colors.primary },
50→    danger: { bg: theme.colors.error, text: '#ffffff' },
51→    ghost: { bg: 'transparent', text: theme.colors.text },
52→  };
53→
54→  const v = variantStyles[variant];
55→  const s = sizeStyles[size];
56→
57→  return (
58→    <TouchableOpacity
59→      onPress={handlePress}
60→      disabled={disabled || loading}
61→      activeOpacity={0.7}
62→      style={[
63→        styles.base,
64→        {
65→          backgroundColor: v.bg,
66→          paddingVertical: s.paddingVertical,
67→          paddingHorizontal: s.paddingHorizontal,
68→          borderWidth: v.border ? 1.5 : 0,
69→          borderColor: v.border || 'transparent',
70→          opacity: disabled ? 0.5 : 1,
71→        },
72→        style,
73→      ]}
74→    >
75→      {loading ? (
76→        <ActivityIndicator color={v.text} size="small" />
77→      ) : (
78→        <Text style={[styles.text, { color: v.text, fontSize: s.fontSize }, textStyle]}>
79→          {title}
80→        </Text>
81→      )}
82→    </TouchableOpacity>
83→  );
84→}
85→
86→const styles = StyleSheet.create({
87→  base: {
88→    borderRadius: theme.borderRadius.md,
89→    alignItems: 'center',
90→    justifyContent: 'center',
91→    flexDirection: 'row',
92→  },
93→  text: {
94→    fontWeight: '600',
95→  },
96→});
